function write_file_data_to_transaction(test_transaction, filename) {
    const specimen = fs.readFileSync(filename, 'utf8')
    const matcher = /[^\n]*([\n]|$)/g

    let line
    do {
        line = matcher.exec(specimen)
        if (line[0] == '') {
            break
        }
        test_transaction.add_data(line[0])
    } while (line[0] != '')

    test_transaction.end_data()
}

